/**
 * CreatePageModal Component - Create new page with multilingual support
 * Author: generated by Amazon Q
 * Created: 2024-01-20
 */

'use client';

import { useState, useEffect } from 'react';
import { X, FileText, Globe } from 'lucide-react';

interface CreatePageModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSuccess?: (pageId: string) => void;
}

export function CreatePageModal({ isOpen, onClose, onSuccess }: CreatePageModalProps) {
  const [pageName, setPageName] = useState('');
  const [slug, setSlug] = useState('');
  const [language, setLanguage] = useState('en');
  const [isDefaultLang, setIsDefaultLang] = useState(true);
  const [pageType, setPageType] = useState<'builder' | 'legacy'>('builder');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const languages = [
    { code: 'en', name: 'English', flag: '🇺🇸' },
    { code: 'ar', name: 'Arabic', flag: '🇸🇦' },
    { code: 'fr', name: 'French', flag: '🇫🇷' },
    { code: 'de', name: 'German', flag: '🇩🇪' },
    { code: 'es', name: 'Spanish', flag: '🇪🇸' }
  ];

  useEffect(() => {
    if (isOpen) {
      setPageName('');
      setSlug('');
      setLanguage('en');
      setIsDefaultLang(true);
      setPageType('builder');
      setError('');
    }
  }, [isOpen]);

  useEffect(() => {
    // تولید خودکار slug از pageName
    if (pageName) {
      const autoSlug = `/${language}/${pageName
        .toLowerCase()
        .replace(/[^a-z0-9]+/g, '-')
        .replace(/^-|-$/g, '')}`;
      setSlug(autoSlug);
    }
  }, [pageName, language]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      // استخراج slug بدون prefix زبان برای PageGroup
      const groupSlug = slug.replace(/^\/(en|ar|fr|de|es)\//, '');

      const res = await fetch('/api/admin/pages', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          title: pageName,
          slug,
          language,
          isDefaultLang,
          isBuilderPage: pageType === 'builder',
          status: 'draft',
          // اطلاعات برای ایجاد PageGroup
          groupName: pageName,
          groupSlug
        })
      });

      const result = await res.json();

      if (result.success) {
        onSuccess?.(result.data.id);
        onClose();
      } else {
        setError(result.error || 'Failed to create page');
      }
    } catch (err) {
      setError('Network error. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm">
      <div className="bg-white dark:bg-slate-800 rounded-lg shadow-xl w-full max-w-lg mx-4">
        {/* Header */}
        <div className="flex items-center justify-between p-6 border-b dark:border-slate-700">
          <div className="flex items-center gap-2">
            <FileText className="text-indigo-600 dark:text-indigo-400" size={24} />
            <h2 className="text-xl font-semibold text-gray-900 dark:text-white">
              Create New Page
            </h2>
          </div>
          <button
            onClick={onClose}
            className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-300 transition-colors"
          >
            <X size={24} />
          </button>
        </div>

        {/* Form */}
        <form onSubmit={handleSubmit} className="p-6 space-y-5">
          {error && (
            <div className="p-3 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded text-sm text-red-600 dark:text-red-400">
              {error}
            </div>
          )}

          {/* Page Name */}
          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
              Page Name *
            </label>
            <input
              type="text"
              value={pageName}
              onChange={(e) => setPageName(e.target.value)}
              placeholder="e.g., Home Page, About Us"
              className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-slate-700 text-gray-900 dark:text-white focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
              required
            />
          </div>

          {/* Language */}
          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
              Language *
            </label>
            <div className="grid grid-cols-3 gap-2">
              {languages.map(lang => (
                <button
                  key={lang.code}
                  type="button"
                  onClick={() => setLanguage(lang.code)}
                  className={`
                    flex items-center gap-2 p-2 border rounded-lg transition-all text-sm
                    ${language === lang.code
                      ? 'border-indigo-500 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-700 dark:text-indigo-300'
                      : 'border-gray-300 dark:border-gray-600 hover:border-indigo-300 dark:hover:border-indigo-700'
                    }
                  `}
                >
                  <span className="text-lg">{lang.flag}</span>
                  <span className="font-medium">{lang.code.toUpperCase()}</span>
                </button>
              ))}
            </div>
          </div>

          {/* Slug */}
          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
              Page Slug *
            </label>
            <input
              type="text"
              value={slug}
              onChange={(e) => setSlug(e.target.value)}
              placeholder={`/${language}/page-name`}
              className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-slate-700 text-gray-900 dark:text-white focus:ring-2 focus:ring-indigo-500 focus:border-transparent font-mono text-sm"
              required
            />
            <p className="mt-1 text-xs text-gray-500 dark:text-gray-400">
              URL path for this page (auto-generated from page name)
            </p>
          </div>

          {/* Default Language */}
          <div>
            <label className="flex items-start gap-3 cursor-pointer">
              <input
                type="checkbox"
                checked={isDefaultLang}
                onChange={(e) => setIsDefaultLang(e.target.checked)}
                className="mt-1 w-4 h-4 text-indigo-600 border-gray-300 rounded focus:ring-indigo-500"
              />
              <div>
                <div className="text-sm font-medium text-gray-900 dark:text-white">
                  Set as default language
                </div>
                <p className="text-xs text-gray-500 dark:text-gray-400 mt-0.5">
                  This will be the primary version of the page
                </p>
              </div>
            </label>
          </div>

          {/* Page Type */}
          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
              Page Type *
            </label>
            <div className="grid grid-cols-2 gap-3">
              <button
                type="button"
                onClick={() => setPageType('builder')}
                className={`
                  p-4 border-2 rounded-lg transition-all text-left
                  ${pageType === 'builder'
                    ? 'border-indigo-500 bg-indigo-50 dark:bg-indigo-900/20'
                    : 'border-gray-300 dark:border-gray-600 hover:border-indigo-300 dark:hover:border-indigo-700'
                  }
                `}
              >
                <div className="font-medium text-gray-900 dark:text-white mb-1">
                  Builder Page
                </div>
                <div className="text-xs text-gray-500 dark:text-gray-400">
                  Visual page builder with sections
                </div>
              </button>

              <button
                type="button"
                onClick={() => setPageType('legacy')}
                className={`
                  p-4 border-2 rounded-lg transition-all text-left
                  ${pageType === 'legacy'
                    ? 'border-indigo-500 bg-indigo-50 dark:bg-indigo-900/20'
                    : 'border-gray-300 dark:border-gray-600 hover:border-indigo-300 dark:hover:border-indigo-700'
                  }
                `}
              >
                <div className="font-medium text-gray-900 dark:text-white mb-1">
                  Legacy Page
                </div>
                <div className="text-xs text-gray-500 dark:text-gray-400">
                  Traditional page format
                </div>
              </button>
            </div>
          </div>

          {/* Info Box */}
          <div className="flex items-start gap-2 p-3 bg-blue-50 dark:bg-blue-900/20 border border-blue-200 dark:border-blue-800 rounded-lg">
            <Globe size={16} className="text-blue-600 dark:text-blue-400 flex-shrink-0 mt-0.5" />
            <div className="text-xs text-blue-800 dark:text-blue-200">
              A new page group will be created. You can add translations later.
            </div>
          </div>

          {/* Actions */}
          <div className="flex gap-3 pt-2">
            <button
              type="button"
              onClick={onClose}
              className="flex-1 px-4 py-2 border border-gray-300 dark:border-gray-600 text-gray-700 dark:text-gray-300 rounded-lg hover:bg-gray-50 dark:hover:bg-slate-700 transition-colors"
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={!pageName || !slug || loading}
              className="flex-1 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors font-medium"
            >
              {loading ? 'Creating...' : 'Create Page'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
